editorial:
**Idea — iterative pointer flip**: Walk the list keeping `prev` (initially null) and `curr` (the head). Save `curr.next`, flip `curr.next = prev`, then slide `prev = curr; curr = next`. When done, `prev` is the new head.

```javascript
// helpers — keep at top of starter + editorial
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}
function listToArray(head) {
  const out = []; while (head) { out.push(head.val); head = head.next; } return out;
}

function reverseTransactionChain(head) {
  let prev = null, curr = head;
  while (curr) {
    const next = curr.next;
    curr.next = prev;
    prev = curr;
    curr = next;
  }
  return prev;
}

function solve(arr) {
  return listToArray(reverseTransactionChain(arrayToList(arr)));
}
```

**Time**: O(n). **Space**: O(1).

Recursive version bhi possible hai but iterative cleanest aur stack overflow ka risk nahi.

