editorial:
**Idea — Floyd's tortoise & hare**: Two pointers, slow advances 1 step, fast advances 2. If a cycle exists, fast eventually laps and meets slow. If fast hits null, no cycle.

```javascript
// helpers — keep at top of starter + editorial
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToListWithCycle(arr, pos) {
  if (arr.length === 0) return null;
  const nodes = arr.map(v => new ListNode(v));
  for (let i = 0; i < nodes.length - 1; i++) nodes[i].next = nodes[i + 1];
  if (pos >= 0 && pos < nodes.length) nodes[nodes.length - 1].next = nodes[pos];
  return nodes[0];
}

function hasDeliveryLoop(head) {
  let slow = head, fast = head;
  while (fast && fast.next) {
    slow = slow.next;
    fast = fast.next.next;
    if (slow === fast) return true;
  }
  return false;
}

function solve(arr, pos) {
  return hasDeliveryLoop(arrayToListWithCycle(arr, pos));
}
```

**Time**: O(n). **Space**: O(1).

HashSet of visited nodes also works but uses O(n) memory. Floyd's is the standard answer.

