function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}

function middleWishlist(head) {
  let slow = head, fast = head;
  while (fast && fast.next) {
    slow = slow.next;
    fast = fast.next.next;
  }
  return slow.val;
}

function solve(arr) {
  return middleWishlist(arrayToList(arr));
}
```

**Time**: O(n). **Space**: O(1).

