**Idea — two-pointer single pass with dummy**: Use a dummy node whose next is head. Push `fast` n+1 steps ahead from dummy, then advance both `fast` and `slow` until fast is null. `slow.next` is now the node to remove.

```javascript
// helpers
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}
function listToArray(head) {
  const out = []; while (head) { out.push(head.val); head = head.next; } return out;
}

function removeNthRecent(head, n) {
  const dummy = new ListNode(0, head);
  let slow = dummy, fast = dummy;
  for (let i = 0; i <= n; i++) fast = fast.next;
  while (fast) { slow = slow.next; fast = fast.next; }
  slow.next = slow.next.next;
  return dummy.next;
}

function solve(arr, n) {
  return listToArray(removeNthRecent(arrayToList(arr), n));
}
```

**Time**: O(length). **Space**: O(1).

Dummy node is the trick — bina iske head removal me extra branching aati hai.

