editorial:
**Idea — dummy node + tail merge**: Walk both lists with two pointers. Always splice the smaller one onto the tail. When one list runs out, attach the rest of the other.

```javascript
// helpers
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}
function listToArray(head) {
  const out = []; while (head) { out.push(head.val); head = head.next; } return out;
}

function mergeUpiQueues(a, b) {
  const dummy = new ListNode();
  let tail = dummy;
  while (a && b) {
    if (a.val <= b.val) { tail.next = a; a = a.next; }
    else { tail.next = b; b = b.next; }
    tail = tail.next;
  }
  tail.next = a || b;
  return dummy.next;
}

function solve(arrA, arrB) {
  return listToArray(mergeUpiQueues(arrayToList(arrA), arrayToList(arrB)));
}
```

**Time**: O(m + n). **Space**: O(1) extra (we splice existing nodes).

