**Idea — dummy + iterative head-insertion**: With dummy in front, walk `pre` to the node just before `left`. Then for `right - left` iterations, take `pre.next.next` and splice it right after `pre`. This rotates the inner segment in place.

```javascript
// helpers
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}
function listToArray(head) {
  const out = []; while (head) { out.push(head.val); head = head.next; } return out;
}

function reverseBetweenBookmarks(head, left, right) {
  const dummy = new ListNode(0, head);
  let pre = dummy;
  for (let i = 1; i < left; i++) pre = pre.next;
  let curr = pre.next;
  for (let i = 0; i < right - left; i++) {
    const moved = curr.next;
    curr.next = moved.next;
    moved.next = pre.next;
    pre.next = moved;
  }
  return dummy.next;
}

function solve(arr, left, right) {
  return listToArray(reverseBetweenBookmarks(arrayToList(arr), left, right));
}
