editorial:
**Idea — close the loop, find new break**: Compute length `n`, set `k %= n`. Connect tail to head making a circle. The new tail is `n - k - 1` steps from the old head; the new head is its `next`. Break the link.

```javascript
// helpers
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}
function listToArray(head) {
  const out = []; while (head) { out.push(head.val); head = head.next; } return out;
}

function rotateDriverShifts(head, k) {
  if (!head || !head.next || k === 0) return head;
  let n = 1, tail = head;
  while (tail.next) { tail = tail.next; n++; }
  k = k % n;
  if (k === 0) return head;
  tail.next = head;
  let newTail = head;
  for (let i = 0; i < n - k - 1; i++) newTail = newTail.next;
  const newHead = newTail.next;
  newTail.next = null;
  return newHead;
}

function solve(arr, k) {
  return listToArray(rotateDriverShifts(arrayToList(arr), k));
}
```

**Time**: O(n). **Space**: O(1).

