editorial:
**Idea — digit-by-digit with carry**: Walk both lists in lockstep. At each step, sum the two digits (treating missing nodes as 0) plus the carry. The new node value is `sum % 10`; carry becomes `floor(sum / 10)`. Continue until both are null AND carry is 0.

```javascript
// helpers
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}
function listToArray(head) {
  const out = []; while (head) { out.push(head.val); head = head.next; } return out;
}

function addTwoBills(a, b) {
  const dummy = new ListNode();
  let tail = dummy, carry = 0;
  while (a || b || carry) {
    const x = a ? a.val : 0;
    const y = b ? b.val : 0;
    const s = x + y + carry;
    tail.next = new ListNode(s % 10);
    carry = Math.floor(s / 10);
    tail = tail.next;
    if (a) a = a.next;
    if (b) b = b.next;
  }
  return dummy.next;
}

function solve(arrA, arrB) {
  return listToArray(addTwoBills(arrayToList(arrA), arrayToList(arrB)));
}
```

**Time**: O(max(m, n)). **Space**: O(max(m, n)) for the result.

