**Idea — two builders**: Maintain two dummy-headed builder chains, one for values `< x` and one for `>= x`. Walk the original list, append each node to the appropriate chain. Finally splice the two together.

```javascript
// helpers
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}
function listToArray(head) {
  const out = []; while (head) { out.push(head.val); head = head.next; } return out;
}

function partitionByThreshold(head, x) {
  const lessDum = new ListNode(), geDum = new ListNode();
  let lessTail = lessDum, geTail = geDum;
  let curr = head;
  while (curr) {
    if (curr.val < x) { lessTail.next = curr; lessTail = curr; }
    else { geTail.next = curr; geTail = curr; }
    curr = curr.next;
  }
  geTail.next = null;
  lessTail.next = geDum.next;
  return lessDum.next;
}

function solve(arr, x) {
  return listToArray(partitionByThreshold(arrayToList(arr), x));
}
```

**Time**: O(n). **Space**: O(1) (reuses nodes).

