function arrayToListWithCycle(arr, pos) {
  if (arr.length === 0) return null;
  const nodes = arr.map(v => new ListNode(v));
  for (let i = 0; i < nodes.length - 1; i++) nodes[i].next = nodes[i + 1];
  if (pos >= 0 && pos < nodes.length) nodes[nodes.length - 1].next = nodes[pos];
  return nodes[0];
}

function cycleEntryPoint(head) {
  let slow = head, fast = head;
  while (fast && fast.next) {
    slow = slow.next;
    fast = fast.next.next;
    if (slow === fast) {
      let p = head;
      while (p !== slow) { p = p.next; slow = slow.next; }
      return p.val;
    }
  }
  return null;
}

function solve(arr, pos) {
  return cycleEntryPoint(arrayToListWithCycle(arr, pos));
}
