editorial:
**Idea — pairwise merge (divide & conquer)**: Merge lists in pairs (1+2, 3+4, ...), halving the count each round. This gives O(N log k) time vs the naive O(Nk) of merging into one accumulator.

```javascript
// helpers
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}
function listToArray(head) {
  const out = []; while (head) { out.push(head.val); head = head.next; } return out;
}

function mergeTwo(a, b) {
  const dummy = new ListNode();
  let t = dummy;
  while (a && b) {
    if (a.val <= b.val) { t.next = a; a = a.next; }
    else { t.next = b; b = b.next; }
    t = t.next;
  }
  t.next = a || b;
  return dummy.next;
}

function mergeKPaymentStreams(lists) {
  if (!lists || lists.length === 0) return null;
  while (lists.length > 1) {
    const merged = [];
    for (let i = 0; i < lists.length; i += 2) {
      const a = lists[i];
      const b = i + 1 < lists.length ? lists[i + 1] : null;
      merged.push(mergeTwo(a, b));
    }
    lists = merged;
  }
  return lists[0];
}

function solve(arrOfArrs) {
  const heads = arrOfArrs.map(arrayToList);
  return listToArray(mergeKPaymentStreams(heads));
}
```

**Time**: O(N log k) where N is total nodes. **Space**: O(1) extra (in-place splicing).

