**Idea — chunked reverse with splice**:
1. Use a dummy node; track `groupPrev` (initially dummy).
2. From `groupPrev`, count `k` nodes ahead; if fewer remain, stop.
3. Reverse the `k` nodes between `groupPrev.next` and `kth`; re-attach.
4. Move `groupPrev` to the new tail (which was the original head of the chunk).

```javascript
// helpers
class ListNode { constructor(val, next) { this.val = val ?? 0; this.next = next ?? null; } }
function arrayToList(arr) {
  const dummy = new ListNode(); let cur = dummy;
  for (const v of arr) { cur.next = new ListNode(v); cur = cur.next; }
  return dummy.next;
}
function listToArray(head) {
  const out = []; while (head) { out.push(head.val); head = head.next; } return out;
}

function reverseCatalogInGroups(head, k) {
  const dummy = new ListNode(0, head);
  let groupPrev = dummy;
  while (true) {
    let kth = groupPrev;
    for (let i = 0; i < k && kth; i++) kth = kth.next;
    if (!kth) break;
    const groupNext = kth.next;
    // reverse from groupPrev.next .. kth
    let prev = groupNext, curr = groupPrev.next;
    while (curr !== groupNext) {
      const n = curr.next;
      curr.next = prev;
      prev = curr;
      curr = n;
    }
    const tmp = groupPrev.next;
    groupPrev.next = kth;
    groupPrev = tmp;
  }
  return dummy.next;
}

function solve(arr, k) {
  return listToArray(reverseCatalogInGroups(arrayToList(arr), k));
}
```

**Time**: O(n). **Space**: O(1).

